        t.addLesson(new Lesson("1. What is a ratio?", "<p>A <strong>ratio</strong> compares two amounts by showing how many of one there are for each of the other. We write it with a colon, like <strong>2 : 3</strong> (say \u201ctwo to three\u201d).</p>" + Doc.analogy("A juice recipe says \u201c2 cups of mango for every 3 cups of water\u201d. That's the ratio 2 : 3. It doesn't fix the total \u2014 you could make a small jug (2 and 3) or a big one (20 and 30); the <em>taste</em> stays the same because the ratio is the same.") + "<h4>Ratios are like fractions in disguise</h4><p>The ratio 2 : 3 behaves just like the fraction 2/3, so you can <strong>scale it up or down</strong> by multiplying or dividing both sides by the same number:</p>" + Doc.formula("2 : 3 = 4 : 6 = 10 : 15 = 20 : 30") + "<h4>Simplifying a ratio</h4><p>Divide both numbers by their HCF to get the simplest form, just like reducing a fraction.</p>" + Doc.example("Simplify 18 : 24", "The HCF of 18 and 24 is 6. Divide both: 18\u00f76 : 24\u00f76 = <strong>3 : 4</strong>.") + Doc.warn("Units must match before you compare. A ratio of 1 metre to 50 cm is <strong>not</strong> 1 : 50 \u2014 convert first: 100 cm : 50 cm = 2 : 1.") + Doc.recap("A ratio compares amounts and can be scaled freely. Simplify by dividing both parts by their HCF."), 1));
