        t.addQuestion(Doc.q("12 workers build a wall in 10 days. How many days for 8 workers (inverse proportion)?", List.of("15", "12", "20", "6.7"), 0, "Work is constant: 12\u00d710 = 8\u00d7d \u2192 d = 120/8 = 15 days.", "MEDIUM"));
